module BlockApps.Solidity.Parse.Parser (parseXabi) where

import Text.Parsec hiding (parse)

import Data.Text (Text)

import BlockApps.Solidity.Parse.File
import BlockApps.Solidity.Parse.ParserTypes

import BlockApps.Solidity.Xabi (Xabi)

-- | The 'parseSolidity' function parses a single Solidity source string (with
-- a given name) into a Haskell data type.  Parser errors are generated by
-- 'Parsec'.
parseXabi :: FileName -> String -> Either ParseError [(Text, Xabi)]
parseXabi = runParser solidityFile "" 

